// Parse the top-5 JSON array returned by the OpenAI node.
// Try common output field names since exact shape can vary by node version.
const response = $input.first().json;
const rawText = response.output || response.text || response.content || response.choices?.[0]?.message?.content || JSON.stringify(response);

let topArticles = [];
try {
  const match = String(rawText).match(/\[[\s\S]*\]/);
  topArticles = JSON.parse(match ? match[0] : rawText);
} catch (e) {
  console.error('Failed to parse top 5 articles:', e.message, rawText);
}

if (!Array.isArray(topArticles) || topArticles.length === 0) {
  const fallback = $('Filter New Articles3').first().json;
  topArticles = [{
    rank: 1,
    title: fallback.title,
    url: fallback.url,
    source: fallback.source,
    description: fallback.description,
    score: 70,
    reason: 'Fallback selection — AI parse error'
  }];
}

return topArticles.map((a) => ({ json: a }));

const items = $input.all();
const rank1 = items.find(i => i.json.rank === 1) || items[0];
return [{ json: rank1.json }];

// Normalize all news sources into a unified schema and deduplicate by URL
const items = $input.all();
const seen = new Set();
const normalized = [];

for (const item of items) {
  const data = item.json;
  let articles = [];

  if (Array.isArray(data.articles) && data.status === 'ok') {
    articles = data.articles
      .filter(a => a.title && a.title !== '[Removed]')
      .map(a => ({
        title: a.title,
        url: a.url,
        description: a.description || '',
        publishedAt: a.publishedAt,
        source: a.source?.name || 'NewsAPI',
        content: a.content || a.description || '',
        _sourceType: 'newsapi'
      }));
  }
  else if (Array.isArray(data.articles) && data.totalArticles !== undefined) {
    articles = data.articles
      .filter(a => a.title)
      .map(a => ({
        title: a.title,
        url: a.url,
        description: a.description || '',
        publishedAt: a.publishedAt,
        source: a.source?.name || 'GNews',
        content: a.content || a.description || '',
        _sourceType: 'gnews'
      }));
  }
  else if (Array.isArray(data.hits)) {
    articles = data.hits
      .filter(a => a.title && a.url)
      .map(a => ({
        title: a.title,
        url: a.url || `https://news.ycombinator.com/item?id=${a.objectID}`,
        description: a.story_text || `${a.points} points on Hacker News`,
        publishedAt: a.created_at,
        source: 'Hacker News',
        content: a.story_text || '',
        _sourceType: 'hackernews'
      }));
  }
  else if (data.link && data.title) {
    articles = [{
      title: data.title,
      url: data.link,
      description: data.contentSnippet || data.summary || '',
      publishedAt: data.isoDate || data.pubDate || new Date().toISOString(),
      source: data.creator || (data.feedUrl?.includes('techcrunch') ? 'TechCrunch' : 'VentureBeat'),
      content: data.content || data.contentSnippet || '',
      _sourceType: 'rss'
    }];
  }

  for (const article of articles) {
    if (article.url && !seen.has(article.url) && article.title) {
      seen.add(article.url);
      normalized.push({ json: article });
    }
  }
}

return normalized.length > 0
  ? normalized
  : [{ json: { _empty: true, title: '', url: '', source: '', description: '', publishedAt: '' } }];

// Filter out articles that have already been published (by URL or similar title)
const publishedRows = $input.all().map(i => i.json);
const newArticles = $('Normalize and Deduplicate3').all().map(i => i.json);

const publishedUrls = new Set(publishedRows.map(r => r.url || r.URL).filter(Boolean));
const publishedTitlesLower = publishedRows
  .map(r => (r.title || r.Title || '').toLowerCase())
  .filter(Boolean);

function isSimilarTitle(title1, title2) {
  const words1 = new Set(title1.toLowerCase().split(/\s+/).filter(w => w.length > 4));
  const words2 = new Set(title2.toLowerCase().split(/\s+/).filter(w => w.length > 4));
  const shared = [...words1].filter(w => words2.has(w));
  return shared.length >= 3;
}

const filtered = newArticles.filter(article => {
  if (!article.url || !article.title || article._empty) return false;
  if (publishedUrls.has(article.url)) return false;
  const tooSimilar = publishedTitlesLower.some(pt => isSimilarTitle(article.title, pt));
  return !tooSimilar;
});

const result = filtered.map(a => ({ json: { ...a, hasArticles: true } }));
return result.length > 0 ? result : [{ json: { hasArticles: false, _empty: true } }];

// Collect all new articles and pass them as a single JSON array to the AI for scoring
const articles = $input.all().map((item, idx) => ({
  index: idx,
  title: item.json.title,
  url: item.json.url,
  source: item.json.source,
  description: item.json.description,
  publishedAt: item.json.publishedAt
}));

return [{ json: { articlesJson: JSON.stringify(articles, null, 2) } }];

const a = $input.first().json;

const title = a.title || '';
const description = (a.description || '').slice(0, 1500);
const url = a.url || '';
const source = (a.source || '').replace(/^[^(]*\(([^)]+)\)$/, '$1').trim();
const score = a.score;

const linkedinPrompt = `You are a senior social media copywriter who writes high-engagement LinkedIn posts for a tech/business audience.

Write ONE LinkedIn post based strictly on the article details below. Do not invent facts not present in the summary.

ARTICLE TITLE: ${title}
SOURCE: ${source}
SUMMARY: ${description}
LINK: ${url}

Rules for the post:
- Start with a scroll-stopping hook line (max 12 words), no emojis in the hook.
- Body: 120-180 words, written in a confident, insightful, first-person analyst voice ("I've been watching...", "Here's what stood out to me...").
- Pull out 2-4 concrete facts/numbers from the summary as bullet points using '→' as the bullet marker.
- Explain in 1-2 sentences why this matters for professionals in tech/marketing/business (the 'so what').
- End with one open-ended question to the reader to drive comments.
- On a new line after the question, add 'Read more: ${url}'.
- On a final new line, add 5-6 relevant hashtags (no spaces inside tags, mix of broad + niche).
- No emojis except optionally 1 in the hook line. No corporate fluff or generic phrases like 'game-changer' or 'in today's fast-paced world'.

Also write a companion image generation prompt: a single descriptive line (30-50 words) for an editorial-style illustration representing the article's core idea, minimalist, no text/logos/faces, suitable for a 16:9 LinkedIn header image.

Return STRICTLY as JSON with no markdown formatting: {"linkedin": "...", "imagePrompt": "..."}`;

return [{
  json: {
    title,
    description,
    url,
    source,
    score,
    linkedinPrompt
  }
}];

const raw = $input.first().json;
const content = raw.message?.content || raw.choices?.[0]?.message?.content || raw.content || '{}';
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { linkedin: content, imagePrompt: '' };
}
return [{ json: parsed }];

const items = $input.all();

for (const item of items) {
  const buffer = await this.helpers.getBinaryDataBuffer(item, 'data');
  const mimeType = item.binary.data.mimeType || 'image/png';

  item.json.image = `data:${mimeType};base64,${buffer.toString('base64')}`;
}

return items;

const items = $input.all();
const results = [];

const linkedinCaption = $('Parse LLM Output').first().json.linkedin || '';

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryData = item.binary && item.binary.data;

  if (!binaryData) {
    throw new Error(`No binary property "data" found on item ${i}`);
  }

  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const mimeType = binaryData.mimeType || 'image/png';
  const base64 = buffer.toString('base64');

  item.json.imageBase64 = base64;
  item.json.title = $('Build LinkedIn Prompt').first().json.title;
  item.json.description = $('Build LinkedIn Prompt').first().json.description || '';
  item.json.source = $('Build LinkedIn Prompt').first().json.source || '';
  item.json.url = $('Build LinkedIn Prompt').first().json.url || '';
  item.json.caption = linkedinCaption;
  item.json.generatedAt = new Date();
  item.json.imageDataUrl = `data:${mimeType};base64,${base64}`;

  results.push(item);
}

return results;

const item = $input.first().json;
const imageUrl = item.body?.imageUrl || item.imageUrl;

if (imageUrl) {
  const matches = imageUrl.match(/^data:(image\/(\w+));base64,(.+)$/);
  if (matches) {
    const mimeType = matches[1];
    const ext = matches[2];
    const base64Data = matches[3];
    return [{
      json: item,
      binary: {
        data: {
          data: base64Data,
          mimeType: mimeType,
          fileName: `image.${ext}`
        }
      }
    }];
  }
}

return [$input.first()];

const webhookBody = $('Webhook').first().json.body;
const imageUrl = webhookBody.imageUrl || null;
const postedAt = new Date().toISOString();

const linkedinPostId = $input.first().json.urn;
const linkedinPostUrl = linkedinPostId ? `https://www.linkedin.com/feed/update/${linkedinPostId}/` : null;

return [{
  json: {
    success: true,
    message: 'Post created successfully on LinkedIn',
    description: webhookBody.description || null,
    imageUrl,
    postedAt,
    results: [
      { platform: 'linkedin', postId: linkedinPostId, postUrl: linkedinPostUrl },
    ]
  }
}];

